import Footer from "../../Components/Footer/Footer";
import Navbar from "../../Components/Navbar/navbar";
import "./AboutUs.css";

function AboutUs() {
  return (
    <>
      <Navbar />
      <section className="about-us">
        <h1>About Us</h1>
        <h3>Our Founding Story</h3>
        <p></p>
      </section>
      <Footer />
    </>
  );
}

export default AboutUs;
